import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"60. Cashing Out Of Annual Leave","description":"","frontmatter":{"title":"60. Cashing Out Of Annual Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","annual-leave"]},"headers":[],"relativePath":"ebas/allied-health/leave/60-cashing-out-of-annual-leave.md","filePath":"ebas/allied-health/leave/60-cashing-out-of-annual-leave.md"}'),l={name:"ebas/allied-health/leave/60-cashing-out-of-annual-leave.md"};function s(r,e,i,u,h,p){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_60-cashing-out-of-annual-leave" tabindex="-1">60. Cashing Out Of Annual Leave <a class="header-anchor" href="#_60-cashing-out-of-annual-leave" aria-label="Permalink to &quot;60. Cashing Out Of Annual Leave&quot;">​</a></h1><p><strong>60.1</strong> An Employee may, with the consent of the Employer, choose to cash out paid annual leave in accordance with this clause 60.</p><p><strong>60.2</strong> Written request and written agreement An Employee wishing to cash out annual leave must make a written request to the Employer, save that the Employer will not unreasonably refuse such a request. Where the Employer agrees to that request, the Employee and the Employer will record the agreement in writing.</p><p><strong>60.3</strong> Terms of agreement must comply with terms</p><p><strong>(a)</strong> A written agreement must comply with the following terms:</p><p><strong>(i)</strong> paid annual leave must not be cashed out if the cashing out would result in the Employee having less than four (4) weeks of accrued annual leave;</p><p><strong>(ii)</strong> each cashing out of a particular amount of paid annual leave must be by a separate agreement in writing between the Employer and the Employee;</p><p><strong>(iii)</strong> the Employee must be paid at least the full amount that would have been payable to the Employee had the Employee taken the leave that the Employee has forgone, including annual leave loading and superannuation to the Employee’s nominated fund; and</p><p><strong>(iv)</strong> an Employee cannot cash out more than four (4) weeks paid annual leave in any 12-month period.</p><p><strong>(b)</strong> An Employee&#39;s accrued annual leave entitlement will be reduced by the amount of annual leave paid out.</p><p><strong>60.4</strong> Part-time Employees – cashing out of annual leave where contracted EFT fraction has reduced A part-time Employee who has reduced their EFT fraction, may request to cash out accrued annual leave in conjunction with taking a period of annual leave so that the total payment for the period is equivalent to the previous EFT fraction. The request and any agreement must comply with the requirements of subclause</p><p><strong>60.3</strong> above save that:</p><p><strong>(a)</strong> paid annual leave must not be cashed out if the cashing out would result in the Employee’s remaining accrued entitlement to paid annual leave being less than four (4) weeks calculated using the new EFT fraction; and</p><p><strong>(b)</strong> the limit on cashing out no more than four (4) weeks annual leave will not apply. Example A part-time Employee recently reduced their contracted EFT from 32 hours per week to 16 hours per week. The Employee wishes to take two (2) weeks annual leave. The Employee&#39;s payment for annual leave taken would be 32 hours&#39; pay (16 hours per week multiplied by two (2)), plus annual leave loading. The Employee has 160 hours of accrued annual leave (i.e. five (5) weeks leave at their previous EFT, or 10 weeks&#39; leave at their new EFT), before taking or cashing out any annual leave. Subject to the Employee complying with this clause 60, the Employee may elect to cash out an additional 32 hours annual leave (plus annual leave loading), at the same time as taking annual leave, so that the total paid to the Employee during the period of leave is: • 32 hours&#39; pay (16 hours per week multiplied by two (2)), plus annual leave loading, for annual leave taken; plus • 32 hours&#39; pay, plus annual leave loading, for annual leave cashed out. At the end of the annual leave period, the Employee retains six (6) weeks&#39; annual leave, at the Employee&#39;s part time hours. That is, the Employee will have:</p><p>160 hours accrued prior to the leave period, minus 32 hours taken, minus 32 hours cashed out = 96 hours (16 hours multiplied by six (6) weeks) accrued annual leave at the end of the leave period.</p><p>Plain language terms: holidays, vacation.</p>',16)])])}const d=a(l,[["render",s]]);export{c as __pageData,d as default};
